window.loadWomen = function () {
    let womenCard = document.getElementById("women-cards");
    women.forEach((item) => {
        let div = document.createElement("div");
        div.className = "div";

        let image = document.createElement("img");
        image.src = item.image;
        div.appendChild(image);

        let heading = document.createElement("p");
        heading.className = "heading";
        heading.textContent = item.heading;
        div.appendChild(heading);

        let cost = document.createElement("p");
        cost.textContent = `Cost :  ${item.cost} `;
        cost.className = "cost";
        div.appendChild(cost);

        let description = document.createElement("p");
        description.textContent = item.description;
        div.appendChild(description);

        let sizeDiv = document.createElement("div");
        sizeDiv.className = "sizeDiv";
        let sizeArray = item.size;
        let sizeSelected = null;
        let selectedButton = document.createElement("button");

        sizeArray.forEach((item) => {
            let sizeButton = document.createElement("button");
            sizeButton.textContent = item;
            sizeDiv.appendChild(sizeButton);
            sizeButton.addEventListener("click", () => {
                selectedButton = sizeButton;
                selectedButton.classList.add("size");
                sizeSelected = item;
            })
        })
        div.appendChild(sizeDiv);

        let button = document.createElement("button");
        button.textContent = "Add to Cart";
        button.className = "cart-button"

        div.appendChild(button);
        button.addEventListener("click", () => {
            if (!sizeSelected) {
                alert("select the size first");
            }
            else {
                selectedButton.classList.remove("size");
                addToCart(item,sizeSelected);
                sizeSelected=null;
            }
        });

        womenCard.appendChild(div);
    })
}

const addToCart = (itemToAdd,size) => {
    let cartItems = JSON.parse(localStorage.getItem("cart")) || [];
    let checkExists = cartItems.find(item => item.heading === itemToAdd.heading);
    if (!checkExists) {
        let finalItem = {
            ...itemToAdd,
            selected:size
        }
        cartItems.push(finalItem);
        localStorage.setItem("cart", JSON.stringify(cartItems));
        alert("Added To Cart");
    }
    else {
        alert("Item Aldready Added In Cart");
    }
}